parameters.jsCode:
const texto = $input.first().json.text;

// Remove backticks, markdown e espaços extras
const limpo = texto
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

try {
  const resultado = JSON.parse(limpo);
  return [{ json: resultado }];
} catch (e) {
  // Se falhar, retorna o texto bruto pra debug
  return [{ json: { erro: e.message, texto_original: limpo } }];
}

